<section class="v4-page-shell"><div class="v4-page-head"><h1>Redirect Manager</h1><p>إدارة تحويلات 301/302 الديناميكية مع عداد hits وتفعيل/تعطيل.</p></div>
<?php if (!empty($flash)): ?><div class="v4-flash v4-flash-<?= e($flash['type'] ?? 'info') ?>"><?= e($flash['message'] ?? '') ?></div><?php endif; ?>
<section class="v4-seo-card"><h2>إضافة / تعديل Redirect</h2><form class="v4-stack-form" method="post" action="<?= e(godyar_v4_base_url('/v4/admin/redirects/save')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="id" value=""><label>Old Path<input type="text" name="old_path" placeholder="/old-path"></label><label>New Path<input type="text" name="new_path" placeholder="/ar/page/about أو https://..."></label><label>Status Code<select name="status_code"><?php foreach ([301,302,307,308] as $code): ?><option value="<?= $code ?>"><?= $code ?></option><?php endforeach; ?></select></label><label class="v4-checkbox"><input type="checkbox" name="is_active" value="1" checked> Active</label><button type="submit">حفظ redirect</button></form></section>
<section class="v4-seo-card"><h2>التحويلات الحالية</h2><?php if (!empty($rows)): ?><div class="v4-table-wrap"><table class="v4-table"><thead><tr><th>ID</th><th>Old</th><th>New</th><th>Code</th><th>Active</th><th>Hits</th><th>إجراء</th></tr></thead><tbody><?php foreach ($rows as $row): ?><tr><td><?= e($row['id'] ?? '') ?></td><td><code><?= e($row['old_path'] ?? '') ?></code></td><td><code><?= e($row['new_path'] ?? '') ?></code></td><td><?= (int)($row['status_code'] ?? 301) ?></td><td><?= (int)($row['is_active'] ?? 1) ? 'نعم' : 'لا' ?></td><td><?= (int)($row['hits'] ?? 0) ?></td><td><details><summary>تعديل</summary><form class="v4-stack-form" method="post" action="<?= e(godyar_v4_base_url('/v4/admin/redirects/save')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="id" value="<?= e($row['id'] ?? '') ?>"><label>Old Path<input type="text" name="old_path" value="<?= e($row['old_path'] ?? '') ?>"></label><label>New Path<input type="text" name="new_path" value="<?= e($row['new_path'] ?? '') ?>"></label><label>Status<select name="status_code"><?php foreach ([301,302,307,308] as $code): ?><option value="<?= $code ?>" <?= ((int)($row['status_code'] ?? 301) === $code) ? 'selected' : '' ?>><?= $code ?></option><?php endforeach; ?></select></label><label class="v4-checkbox"><input type="checkbox" name="is_active" value="1" <?= (int)($row['is_active'] ?? 1) ? 'checked' : '' ?>> Active</label><button type="submit" class="v4-btn-ghost">تحديث</button></form><form class="v4-inline-form" method="post" action="<?= e(godyar_v4_base_url('/v4/admin/redirects/delete')) ?>" onsubmit="return confirm('حذف هذا الـ redirect؟');"><?= godyar_v4_csrf_field() ?><input type="hidden" name="id" value="<?= e($row['id'] ?? '') ?>"><button type="submit" class="v4-btn-danger">حذف</button></form></details></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><div class="v4-empty-state"><p>لا توجد تحويلات محفوظة بعد.</p></div><?php endif; ?></section></section>
